import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { 
  FaDownload, FaEye, FaBook, FaFilePdf, FaFileAlt, 
  FaQuestionCircle, FaHistory, FaArrowLeft, FaBookOpen, 
  FaClock, FaStar, FaSpinner, FaUser, FaSearch,
  FaFilter, FaFileWord, FaFilePowerpoint, FaFileImage,
  FaFileArchive, FaPrint, FaSync, FaCloudUploadAlt
} from 'react-icons/fa';
import { coursesData, getSubjects } from '../data/coursesData';
import api from '../services/api'; // ✅ API import

const MaterialsPage = () => {
  const { courseId, yearId, semId, subjectId } = useParams();
  const navigate = useNavigate();
  
  const [subject, setSubject] = useState(null);
  const [materials, setMaterials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedType, setSelectedType] = useState('all');
  const [downloading, setDownloading] = useState({});
  const [searchQuery, setSearchQuery] = useState('');
  const [courseInfo, setCourseInfo] = useState(null);
  const [error, setError] = useState(null);
  const [lastRefreshed, setLastRefreshed] = useState(new Date());

  // Material types
  const materialTypes = [
    { id: 'all', name: 'All Materials', icon: <FaFilter />, color: '#6b7280' },
    { id: 'syllabus', name: 'Syllabus', icon: <FaBook />, color: '#3B82F6' },
    { id: 'notes', name: 'Notes', icon: <FaFileAlt />, color: '#10B981' },
    { id: 'pyq', name: 'PYQs', icon: <FaHistory />, color: '#8B5CF6' },
    { id: 'important', name: 'Imp Questions', icon: <FaQuestionCircle />, color: '#F59E0B' },
    { id: 'lab', name: 'Lab Manuals', icon: <FaBookOpen />, color: '#EF4444' },
    { id: 'assignment', name: 'Assignments', icon: <FaFilePdf />, color: '#EC4899' }
  ];

  // ✅ PREVIEW FUNCTION
  const handlePreview = (material) => {
    const previewContent = `
      <div style="padding: 20px; max-width: 500px;">
        <h3 style="color: #1f2937; margin-bottom: 10px;">${material.title}</h3>
        <p style="color: #6b7280; margin-bottom: 15px;">${material.description}</p>
        <div style="background: #f9fafb; padding: 15px; border-radius: 8px; margin-bottom: 15px;">
          <p style="margin: 5px 0;"><strong>📁 File Type:</strong> ${material.fileType.toUpperCase()}</p>
          <p style="margin: 5px 0;"><strong>📏 File Size:</strong> ${material.fileSize}</p>
          <p style="margin: 5px 0;"><strong>📖 Pages:</strong> ${material.pages}</p>
          <p style="margin: 5px 0;"><strong>👤 Uploaded by:</strong> ${material.user}</p>
          <p style="margin: 5px 0;"><strong>📅 Upload Date:</strong> ${material.uploadDate}</p>
          <p style="margin: 5px 0;"><strong>⭐ Rating:</strong> ${material.rating}/5</p>
          <p style="margin: 5px 0;"><strong>📥 Downloads:</strong> ${material.downloads}</p>
          <p style="margin: 5px 0;"><strong>👁️ Views:</strong> ${material.views}</p>
        </div>
        <div style="display: flex; gap: 10px; margin-top: 20px;">
          <button onclick="handlePreviewDownload()" style="flex: 1; padding: 10px; background: #10b981; color: white; border: none; border-radius: 6px; cursor: pointer;">
            Download Now
          </button>
          <button onclick="window.closeModal()" style="flex: 1; padding: 10px; background: #6b7280; color: white; border: none; border-radius: 6px; cursor: pointer;">
            Close
          </button>
        </div>
      </div>
    `;

    const modal = document.createElement('div');
    modal.id = 'previewModal';
    modal.style.cssText = `
      position: fixed;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: rgba(0,0,0,0.5);
      display: flex;
      justify-content: center;
      align-items: center;
      z-index: 1000;
    `;
    
    const modalContent = document.createElement('div');
    modalContent.style.cssText = `
      background: white;
      border-radius: 12px;
      padding: 0;
      max-width: 600px;
      width: 90%;
      max-height: 80vh;
      overflow-y: auto;
      box-shadow: 0 20px 25px -5px rgba(0,0,0,0.1);
    `;
    modalContent.innerHTML = previewContent;
    
    modal.appendChild(modalContent);
    document.body.appendChild(modal);
    
    window.closeModal = () => {
      document.body.removeChild(modal);
    };
    
    modal.addEventListener('click', (e) => {
      if (e.target === modal) {
        window.closeModal();
      }
    });
    
    window.handlePreviewDownload = () => {
      handleDownload(material);
      window.closeModal();
    };
  };

  // ✅ DOWNLOAD FUNCTION with API tracking
  const handleDownload = async (material) => {
    setDownloading(prev => ({ ...prev, [material.id]: true }));
    
    try {
      // Track download in backend if it's a real material
      if (material.id && typeof material.id === 'number' && material.id < 1000) {
        await api.downloadMaterial(material.id, `${material.title}.pdf`).catch(err => 
          console.log('Download tracking failed:', err)
        );
      }
      
      // Create file for download
      const fileName = `${material.title.replace(/[^a-zA-Z0-9]/g, '_')}.${material.fileType}`;
      const fileContent = `=== STUDY PORTAL - ${material.title} ===\n\n` +
        `Subject: ${subject?.name || 'Unknown'}\n` +
        `Code: ${subject?.code || 'N/A'}\n` +
        `Type: ${material.type}\n` +
        `Description: ${material.description}\n\n` +
        `File Information:\n` +
        `- Format: ${material.fileType.toUpperCase()}\n` +
        `- Size: ${material.fileSize}\n` +
        `- Pages: ${material.pages}\n` +
        `- Uploaded by: ${material.user}\n` +
        `- Upload Date: ${material.uploadDate}\n\n` +
        `=== This is a demo file. In the actual application, real PDF files would be downloaded. ===\n` +
        `Downloaded from Notes Hub Study Portal on ${new Date().toLocaleString()}`;
      
      setTimeout(() => {
        const blob = new Blob([fileContent], { type: 'text/plain' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = fileName;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        window.URL.revokeObjectURL(url);
        
        // Show success notification
        showNotification('Download Complete!', material.title, 'success');
        
        // Update download count in UI
        setMaterials(prev =>
          prev.map(m =>
            m.id === material.id
              ? { ...m, downloads: m.downloads + 1 }
              : m
          )
        );
        
        setDownloading(prev => ({ ...prev, [material.id]: false }));
      }, 1000);
      
    } catch (error) {
      console.error('Download error:', error);
      showNotification('Download Failed', error.message, 'error');
      setDownloading(prev => ({ ...prev, [material.id]: false }));
    }
  };

  // ✅ Notification helper
  const showNotification = (title, message, type = 'success') => {
    const notification = document.createElement('div');
    notification.style.cssText = `
      position: fixed;
      top: 20px;
      right: 20px;
      background: ${type === 'success' ? 'linear-gradient(135deg, #10b981, #34d399)' : 'linear-gradient(135deg, #ef4444, #f87171)'};
      color: white;
      padding: 15px 20px;
      border-radius: 8px;
      box-shadow: 0 4px 12px ${type === 'success' ? 'rgba(16, 185, 129, 0.3)' : 'rgba(239, 68, 68, 0.3)'};
      z-index: 9999;
      display: flex;
      align-items: center;
      gap: 10px;
      animation: slideIn 0.3s ease;
    `;
    
    notification.innerHTML = `
      <div style="font-size: 20px;">${type === 'success' ? '✅' : '❌'}</div>
      <div>
        <div style="font-weight: 600;">${title}</div>
        <div style="font-size: 14px; opacity: 0.9;">${message}</div>
      </div>
    `;
    
    document.body.appendChild(notification);
    
    setTimeout(() => {
      notification.style.animation = 'slideOut 0.3s ease';
      setTimeout(() => {
        if (notification.parentNode) {
          document.body.removeChild(notification);
        }
      }, 300);
    }, 3000);
  };

  // ✅ FETCH MATERIALS FROM BACKEND (MAIN FIX)
  const fetchMaterialsFromBackend = async (showRefreshIndicator = false) => {
    if (showRefreshIndicator) setRefreshing(true);
    
    try {
      setError(null);
      
      console.log('Fetching materials for subject:', subjectId);
      
      // Try to get real data from backend
      let response;
      try {
        response = await api.getMaterials({
          subject_id: subjectId,
          status: 'approved'
        });
      } catch (apiError) {
        console.log('API error, using mock data:', apiError);
        response = { notes: [] };
      }
      
      console.log('API Response:', response);
      
      let transformedMaterials = [];
      
      if (response && response.notes && response.notes.length > 0) {
        // Transform backend data to frontend format
        transformedMaterials = response.notes.map((note, index) => ({
          id: note.id || index + 1000,
          title: note.title || 'Untitled',
          type: note.material_type || note.type || 'notes',
          description: note.description || 'No description available',
          fileSize: note.file_size || formatBytes(note.file_size_bytes) || '1.2 MB',
          pages: note.pages || Math.floor(Math.random() * 30) + 10,
          uploadDate: note.uploaded_at ? new Date(note.uploaded_at).toLocaleDateString('en-IN', {
            day: 'numeric',
            month: 'short',
            year: 'numeric'
          }) : new Date().toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' }),
          downloads: note.downloads || Math.floor(Math.random() * 200) + 50,
          views: note.views || Math.floor(Math.random() * 500) + 100,
          rating: note.rating || (4 + Math.random()).toFixed(1),
          fileUrl: note.file_url || '#',
          fileType: note.file_type || 'pdf',
          user: note.user_name || note.uploader_name || 'Student',
          isNew: note.uploaded_at ? new Date(note.uploaded_at) > new Date(Date.now() - 7*24*60*60*1000) : true
        }));
      }
      
      // If no data from backend, generate mock data based on subject
      if (transformedMaterials.length === 0 && subject) {
        console.log('No backend data, generating mock materials');
        transformedMaterials = generateMockMaterials(subject);
      }
      
      setMaterials(transformedMaterials);
      setLastRefreshed(new Date());
      
    } catch (error) {
      console.error('Error fetching materials:', error);
      setError('Failed to load materials from server. Showing sample data.');
      
      // Fallback to mock data
      if (subject) {
        const mockMaterials = generateMockMaterials(subject);
        setMaterials(mockMaterials);
      }
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  };

  // ✅ Format bytes helper
  const formatBytes = (bytes) => {
    if (!bytes) return null;
    const units = ['B', 'KB', 'MB', 'GB'];
    let size = bytes;
    let unitIndex = 0;
    while (size >= 1024 && unitIndex < units.length - 1) {
      size /= 1024;
      unitIndex++;
    }
    return `${size.toFixed(1)} ${units[unitIndex]}`;
  };

  // ✅ Generate mock materials (fallback)
  const generateMockMaterials = (subjectData) => {
    const baseMaterials = [
      {
        id: 1,
        title: `${subjectData.name} - Complete Syllabus`,
        type: 'syllabus',
        description: `Official syllabus for ${subjectData.name} with unit-wise distribution, marking scheme, and recommended books`,
        fileSize: '1.2 MB',
        pages: 12,
        uploadDate: '15 Jan 2024',
        downloads: subjectData.materials * 10 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 20 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating || 4.5).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'University Admin',
        isNew: true
      },
      {
        id: 2,
        title: `${subjectData.name} - Complete Notes`,
        type: 'notes',
        description: `Comprehensive notes covering all topics of ${subjectData.name} with examples, diagrams, and explanations`,
        fileSize: '4.5 MB',
        pages: 45,
        uploadDate: '20 Jan 2024',
        downloads: subjectData.materials * 15 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 30 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating + 0.3 || 4.8).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Professor Sharma',
        isNew: true
      },
      {
        id: 3,
        title: `${subjectData.name} - PYQ (2020-2024)`,
        type: 'pyq',
        description: `Previous year question papers with detailed solutions for last 5 years`,
        fileSize: '3.2 MB',
        pages: 35,
        uploadDate: '05 Jan 2024',
        downloads: subjectData.materials * 20 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 40 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating + 0.4 || 4.9).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Exam Cell',
        isNew: false
      },
      {
        id: 4,
        title: `${subjectData.name} - Important Questions`,
        type: 'important',
        description: `Most expected questions and important topics for exams with answers`,
        fileSize: '1.5 MB',
        pages: 18,
        uploadDate: '22 Jan 2024',
        downloads: subjectData.materials * 12 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 25 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating + 0.1 || 4.6).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Faculty',
        isNew: true
      },
      {
        id: 5,
        title: `${subjectData.name} - Reference Books`,
        type: 'notes',
        description: `List of recommended books and reference materials with download links`,
        fileSize: '0.8 MB',
        pages: 8,
        uploadDate: '10 Jan 2024',
        downloads: subjectData.materials * 8 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 15 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating || 4.5).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Library',
        isNew: false
      }
    ];

    // Add lab manual for lab subjects
    if (subjectData.type === 'Lab' || subjectData.name.toLowerCase().includes('lab')) {
      baseMaterials.push({
        id: 6,
        title: `${subjectData.name} - Lab Manual`,
        type: 'lab',
        description: `Complete lab manual with experiments, procedures, observations, and viva questions`,
        fileSize: '2.8 MB',
        pages: 32,
        uploadDate: '18 Jan 2024',
        downloads: subjectData.materials * 8 + Math.floor(Math.random() * 50),
        views: subjectData.materials * 18 + Math.floor(Math.random() * 100),
        rating: (subjectData.rating + 0.2 || 4.7).toFixed(1),
        fileUrl: '#',
        fileType: 'pdf',
        user: 'Lab Incharge',
        isNew: true
      });
    }

    // Add assignments
    baseMaterials.push({
      id: 7,
      title: `${subjectData.name} - Assignments`,
      type: 'assignment',
      description: `Solved assignments and practice problems with solutions`,
      fileSize: '2.1 MB',
      pages: 25,
      uploadDate: '25 Jan 2024',
      downloads: subjectData.materials * 9 + Math.floor(Math.random() * 50),
      views: subjectData.materials * 22 + Math.floor(Math.random() * 100),
      rating: (subjectData.rating + 0.1 || 4.6).toFixed(1),
      fileUrl: '#',
      fileType: 'pdf',
      user: 'Teaching Assistant',
      isNew: true
    });

    return baseMaterials;
  };

  // ✅ Initial load and auto-refresh
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      
      try {
        // Get subject info from local data
        const subjects = getSubjects(parseInt(courseId), parseInt(yearId), parseInt(semId));
        const foundSubject = subjects.find(sub => sub.id === parseInt(subjectId));
        
        if (foundSubject) {
          setSubject(foundSubject);
          setCourseInfo(coursesData[courseId]);
          
          // Fetch materials from backend
          await fetchMaterialsFromBackend();
        } else {
          setError('Subject not found in course data');
          setLoading(false);
        }
      } catch (error) {
        console.error('Error loading subject:', error);
        setError('Failed to load subject information');
        setLoading(false);
      }
    };
    
    loadData();
    
    // Auto-refresh every 30 seconds to get newly approved materials
    const interval = setInterval(() => {
      if (subject) {
        console.log('Auto-refreshing materials...');
        fetchMaterialsFromBackend(true);
      }
    }, 30000);
    
    return () => clearInterval(interval);
  }, [courseId, yearId, semId, subjectId]);

  // Handle back navigation
  const handleBack = () => {
    navigate(`/course/${courseId}/year/${yearId}/sem/${semId}`);
  };

  // Handle manual refresh
  const handleRefresh = () => {
    fetchMaterialsFromBackend(true);
  };

  // Filter materials
  const filteredMaterials = materials.filter(material => {
    const matchesType = selectedType === 'all' || material.type === selectedType;
    const matchesSearch = searchQuery === '' ||
      material.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
      material.description.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (material.user && material.user.toLowerCase().includes(searchQuery.toLowerCase()));
    return matchesType && matchesSearch;
  });

  // Get file icon
  const getFileIcon = (fileType) => {
    const type = fileType?.toLowerCase() || 'pdf';
    if (type.includes('pdf')) return <FaFilePdf style={{ color: '#ef4444' }} />;
    if (type.includes('doc') || type.includes('word')) return <FaFileWord style={{ color: '#2563eb' }} />;
    if (type.includes('ppt') || type.includes('powerpoint')) return <FaFilePowerpoint style={{ color: '#f97316' }} />;
    if (type.includes('jpg') || type.includes('png') || type.includes('jpeg')) return <FaFileImage style={{ color: '#8b5cf6' }} />;
    if (type.includes('zip') || type.includes('rar')) return <FaFileArchive style={{ color: '#6b7280' }} />;
    return <FaFileAlt style={{ color: '#6b7280' }} />;
  };

  // Calculate stats
  const getMaterialStats = () => {
    const stats = {};
    materialTypes.forEach(type => {
      if (type.id !== 'all') {
        stats[type.id] = materials.filter(m => m.type === type.id).length;
      }
    });
    return stats;
  };

  const materialStats = getMaterialStats();

  // Styles
  const styles = {
    container: {
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px',
      fontFamily: '"Segoe UI", Tahoma, Geneva, Verdana, sans-serif'
    },
    innerContainer: {
      maxWidth: '1200px',
      margin: '0 auto'
    },
    headerButtons: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '20px',
      flexWrap: 'wrap',
      gap: '15px'
    },
    backButton: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: '8px',
      padding: '12px 24px',
      background: 'white',
      color: '#4f46e5',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      transition: 'all 0.3s ease'
    },
    refreshButton: {
      display: 'inline-flex',
      alignItems: 'center',
      gap: '8px',
      padding: '12px 24px',
      background: '#10b981',
      color: 'white',
      border: 'none',
      borderRadius: '8px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '16px',
      boxShadow: '0 4px 6px rgba(16, 185, 129, 0.3)',
      transition: 'all 0.3s ease'
    },
    subjectHeader: {
      background: 'white',
      padding: '30px',
      borderRadius: '16px',
      marginBottom: '30px',
      boxShadow: '0 10px 25px rgba(0, 0, 0, 0.1)',
      display: 'flex',
      alignItems: 'center',
      gap: '25px',
      flexWrap: 'wrap'
    },
    subjectIconContainer: {
      width: '90px',
      height: '90px',
      borderRadius: '50%',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      flexShrink: '0'
    },
    subjectIcon: {
      fontSize: '40px',
      color: 'white'
    },
    subjectInfo: {
      flex: '1'
    },
    subjectName: {
      fontSize: '32px',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '10px'
    },
    subjectCode: {
      fontSize: '18px',
      color: '#6b7280',
      marginBottom: '15px',
      display: 'flex',
      alignItems: 'center',
      gap: '20px',
      flexWrap: 'wrap'
    },
    breadcrumb: {
      display: 'flex',
      alignItems: 'center',
      gap: '10px',
      fontSize: '14px',
      color: '#9ca3af',
      flexWrap: 'wrap'
    },
    breadcrumbItem: {
      padding: '6px 12px',
      background: '#f3f4f6',
      borderRadius: '6px'
    },
    currentBreadcrumb: {
      background: '#4f46e5',
      color: 'white'
    },
    statsBox: {
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px',
      borderRadius: '12px',
      color: 'white',
      textAlign: 'center',
      minWidth: '120px'
    },
    statsNumber: {
      fontSize: '32px',
      fontWeight: '700',
      marginBottom: '5px'
    },
    statsLabel: {
      fontSize: '14px',
      opacity: '0.9'
    },
    lastRefreshed: {
      fontSize: '12px',
      color: '#9ca3af',
      marginTop: '10px',
      textAlign: 'right'
    }
  };

  // Loading state
  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <div style={{ textAlign: 'center', padding: '100px', background: 'white', borderRadius: '16px' }}>
            <div style={{
              width: '50px',
              height: '50px',
              border: '5px solid #f3f4f6',
              borderTop: '5px solid #4f46e5',
              borderRadius: '50%',
              margin: '0 auto 20px',
              animation: 'spin 1s linear infinite'
            }}></div>
            <h3 style={{ color: '#6b7280' }}>Loading Study Materials...</h3>
            <p style={{ color: '#9ca3af', marginTop: '10px' }}>Fetching latest content for you</p>
          </div>
        </div>
      </div>
    );
  }

  // Subject not found
  if (!subject) {
    return (
      <div style={styles.container}>
        <div style={styles.innerContainer}>
          <button style={styles.backButton} onClick={() => navigate(-1)}>
            <FaArrowLeft /> Back
          </button>
          <div style={{ background: 'white', padding: '60px', borderRadius: '16px', textAlign: 'center' }}>
            <div style={{ fontSize: '60px', marginBottom: '20px' }}>🔍</div>
            <h2 style={{ fontSize: '24px', color: '#1f2937', marginBottom: '10px' }}>Subject not found</h2>
            <p style={{ color: '#6b7280' }}>The requested subject could not be found in our database.</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
        @keyframes slideIn {
          from { transform: translateX(100%); opacity: 0; }
          to { transform: translateX(0); opacity: 1; }
        }
        @keyframes slideOut {
          from { transform: translateX(0); opacity: 1; }
          to { transform: translateX(100%); opacity: 0; }
        }
      `}</style>
      
      <div style={styles.innerContainer}>
        
        {/* Header with Back and Refresh buttons */}
        <div style={styles.headerButtons}>
          <button 
            style={styles.backButton}
            onClick={handleBack}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = '#f3f4f6';
              e.currentTarget.style.transform = 'translateY(-2px)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'white';
              e.currentTarget.style.transform = 'none';
            }}
          >
            <FaArrowLeft /> Back to Subjects
          </button>
          
          <div style={{ display: 'flex', gap: '10px' }}>
            <button 
              style={styles.refreshButton}
              onClick={handleRefresh}
              disabled={refreshing}
              onMouseEnter={(e) => {
                if (!refreshing) {
                  e.currentTarget.style.background = '#059669';
                  e.currentTarget.style.transform = 'translateY(-2px)';
                }
              }}
              onMouseLeave={(e) => {
                if (!refreshing) {
                  e.currentTarget.style.background = '#10b981';
                  e.currentTarget.style.transform = 'none';
                }
              }}
            >
              <FaSync style={{ animation: refreshing ? 'spin 1s linear infinite' : 'none' }} />
              {refreshing ? 'Refreshing...' : 'Refresh Materials'}
            </button>
            
            <button 
              style={{
                ...styles.refreshButton,
                background: '#8b5cf6'
              }}
              onClick={() => navigate('/upload')}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = '#7c3aed';
                e.currentTarget.style.transform = 'translateY(-2px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = '#8b5cf6';
                e.currentTarget.style.transform = 'none';
              }}
            >
              <FaCloudUploadAlt /> Upload Materials
            </button>
          </div>
        </div>
        
        {/* Error Message */}
        {error && (
          <div style={{
            background: '#fee2e2',
            color: '#dc2626',
            padding: '15px',
            borderRadius: '8px',
            marginBottom: '20px',
            textAlign: 'center',
            border: '1px solid #fecaca'
          }}>
            <strong>⚠️ {error}</strong>
          </div>
        )}
        
        {/* Last Refreshed */}
        <div style={styles.lastRefreshed}>
          Last updated: {lastRefreshed.toLocaleTimeString()}
        </div>
        
        {/* Subject Header */}
        <div style={styles.subjectHeader}>
          <div style={styles.subjectIconContainer}>
            <div style={styles.subjectIcon}>📚</div>
          </div>
          
          <div style={styles.subjectInfo}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '20px' }}>
              <div>
                <h1 style={styles.subjectName}>{subject.name}</h1>
                <div style={styles.subjectCode}>
                  <span>Code: <strong>{subject.code}</strong></span>
                  <span>⭐ <strong>{subject.credits} Credits</strong></span>
                  <span>📁 <strong>{materials.length} Materials</strong></span>
                  <span>🏷️ <strong>{subject.type || 'Theory'}</strong></span>
                </div>
                
                <div style={styles.breadcrumb}>
                  <span style={styles.breadcrumbItem}>
                    {courseInfo?.name || `Course ${courseId}`}
                  </span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>
                    Year {yearId}
                  </span>
                  <span>→</span>
                  <span style={styles.breadcrumbItem}>
                    Semester {semId}
                  </span>
                  <span>→</span>
                  <span style={{ ...styles.breadcrumbItem, ...styles.currentBreadcrumb }}>
                    {subject.name}
                  </span>
                </div>
              </div>
              
              <div style={styles.statsBox}>
                <div style={styles.statsNumber}>{materials.length}</div>
                <div style={styles.statsLabel}>Total Files</div>
                <div style={{ ...styles.statsLabel, fontSize: '12px', marginTop: '5px' }}>
                  {materials.filter(m => m.isNew).length} New
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Search Bar */}
        <div style={{
          background: 'white',
          padding: '20px',
          borderRadius: '12px',
          marginBottom: '25px',
          boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
        }}>
          <div style={{ position: 'relative' }}>
            <input
              type="text"
              placeholder={`Search in ${subject.name} materials...`}
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              style={{
                width: '100%',
                padding: '16px 20px 16px 50px',
                fontSize: '16px',
                border: '2px solid #e5e7eb',
                borderRadius: '10px',
                background: '#f9fafb',
                transition: 'all 0.3s',
                outline: 'none'
              }}
              onFocus={(e) => {
                e.target.style.borderColor = '#4f46e5';
                e.target.style.boxShadow = '0 0 0 3px rgba(79, 70, 229, 0.1)';
              }}
              onBlur={(e) => {
                e.target.style.borderColor = '#e5e7eb';
                e.target.style.boxShadow = 'none';
              }}
            />
            <div style={{
              position: 'absolute',
              left: '20px',
              top: '50%',
              transform: 'translateY(-50%)',
              color: '#9ca3af',
              fontSize: '18px'
            }}>
              <FaSearch />
            </div>
            {searchQuery && (
              <button
                style={{
                  position: 'absolute',
                  right: '20px',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  color: '#9ca3af',
                  cursor: 'pointer',
                  fontSize: '18px',
                  padding: '5px 10px'
                }}
                onClick={() => setSearchQuery('')}
                onMouseEnter={(e) => {
                  e.currentTarget.style.color = '#6b7280';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.color = '#9ca3af';
                }}
              >
                ✕
              </button>
            )}
          </div>
        </div>

        {/* Filter Buttons */}
        <div style={{
          background: 'white',
          padding: '20px',
          borderRadius: '12px',
          marginBottom: '25px',
          boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
        }}>
          <h3 style={{
            fontSize: '20px',
            fontWeight: '600',
            color: '#1f2937',
            marginBottom: '15px',
            display: 'flex',
            alignItems: 'center',
            gap: '8px'
          }}>
            <FaFilter /> Filter by Material Type
          </h3>
          <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
            {materialTypes.map((type) => (
              <button
                key={type.id}
                onClick={() => setSelectedType(type.id)}
                style={{
                  padding: '12px 20px',
                  border: `2px solid ${selectedType === type.id ? type.color : '#e5e7eb'}`,
                  borderRadius: '8px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '8px',
                  fontSize: '14px',
                  fontWeight: '500',
                  background: selectedType === type.id ? `${type.color}15` : 'white',
                  color: selectedType === type.id ? type.color : '#4b5563',
                  transition: 'all 0.3s'
                }}
                onMouseEnter={(e) => {
                  if (selectedType !== type.id) {
                    e.currentTarget.style.borderColor = type.color;
                    e.currentTarget.style.background = `${type.color}10`;
                  }
                }}
                onMouseLeave={(e) => {
                  if (selectedType !== type.id) {
                    e.currentTarget.style.borderColor = '#e5e7eb';
                    e.currentTarget.style.background = 'white';
                  }
                }}
              >
                <span style={{ color: type.color }}>{type.icon}</span>
                {type.name}
                {type.id !== 'all' && (
                  <span style={{
                    background: '#f3f4f6',
                    color: '#6b7280',
                    padding: '2px 8px',
                    borderRadius: '12px',
                    fontSize: '12px',
                    fontWeight: 'bold'
                  }}>
                    {materialStats[type.id] || 0}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Materials Grid */}
        {filteredMaterials.length === 0 ? (
          <div style={{
            background: 'white',
            padding: '60px 20px',
            borderRadius: '12px',
            textAlign: 'center',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ fontSize: '60px', marginBottom: '20px', opacity: '0.5' }}>📭</div>
            <h3 style={{ fontSize: '24px', fontWeight: '600', color: '#6b7280', marginBottom: '10px' }}>
              No materials found
            </h3>
            <p style={{ color: '#9ca3af', fontSize: '16px', marginBottom: '30px', maxWidth: '400px', margin: '0 auto 30px' }}>
              {searchQuery 
                ? `No materials match "${searchQuery}"`
                : selectedType !== 'all'
                ? `No ${materialTypes.find(t => t.id === selectedType)?.name.toLowerCase()} available for this subject yet.`
                : 'No approved materials available yet. Check back later or upload new materials.'}
            </p>
            <div style={{ display: 'flex', gap: '15px', justifyContent: 'center' }}>
              <button
                style={{
                  padding: '12px 30px',
                  background: '#4f46e5',
                  color: 'white',
                  border: 'none',
                  borderRadius: '8px',
                  cursor: 'pointer',
                  fontWeight: '600',
                  fontSize: '16px',
                  transition: 'all 0.3s'
                }}
                onClick={() => navigate('/upload')}
                onMouseEnter={(e) => {
                  e.currentTarget.style.background = '#4338ca';
                  e.currentTarget.style.transform = 'translateY(-2px)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.background = '#4f46e5';
                  e.currentTarget.style.transform = 'none';
                }}
              >
                <FaCloudUploadAlt style={{ marginRight: '8px' }} />
                Upload Materials
              </button>
              {searchQuery && (
                <button
                  style={{
                    padding: '12px 30px',
                    background: '#6b7280',
                    color: 'white',
                    border: 'none',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    fontWeight: '600',
                    fontSize: '16px',
                    transition: 'all 0.3s'
                  }}
                  onClick={() => setSearchQuery('')}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = '#4b5563';
                    e.currentTarget.style.transform = 'translateY(-2px)';
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = '#6b7280';
                    e.currentTarget.style.transform = 'none';
                  }}
                >
                  Clear Search
                </button>
              )}
            </div>
          </div>
        ) : (
          <div style={{
            background: 'white',
            padding: '30px',
            borderRadius: '12px',
            boxShadow: '0 4px 6px rgba(0,0,0,0.05)'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px', flexWrap: 'wrap', gap: '15px' }}>
              <h3 style={{ fontSize: '24px', fontWeight: '700', color: '#1f2937' }}>
                {selectedType === 'all' ? 'All Study Materials' : materialTypes.find(t => t.id === selectedType)?.name}
              </h3>
              <span style={{ 
                background: '#f3f4f6',
                padding: '5px 15px',
                borderRadius: '20px',
                color: '#6b7280',
                fontWeight: '500'
              }}>
                {filteredMaterials.length} material{filteredMaterials.length !== 1 ? 's' : ''}
              </span>
            </div>
            
            <div style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))',
              gap: '25px'
            }}>
              {filteredMaterials.map((material) => {
                const typeInfo = materialTypes.find(t => t.id === material.type) || materialTypes[1];
                
                return (
                  <div
                    key={material.id}
                    style={{
                      border: '1px solid #e5e7eb',
                      borderRadius: '12px',
                      overflow: 'hidden',
                      transition: 'all 0.4s ease',
                      background: 'white',
                      position: 'relative'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.transform = 'translateY(-5px)';
                      e.currentTarget.style.boxShadow = '0 20px 40px rgba(0, 0, 0, 0.1)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.transform = 'none';
                      e.currentTarget.style.boxShadow = 'none';
                    }}
                  >
                    {/* New Badge */}
                    {material.isNew && (
                      <div style={{
                        position: 'absolute',
                        top: '10px',
                        right: '10px',
                        background: '#ef4444',
                        color: 'white',
                        padding: '4px 12px',
                        borderRadius: '20px',
                        fontSize: '12px',
                        fontWeight: 'bold',
                        zIndex: 1,
                        boxShadow: '0 2px 4px rgba(239, 68, 68, 0.3)'
                      }}>
                        NEW
                      </div>
                    )}
                    
                    {/* Header */}
                    <div style={{
                      padding: '18px',
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      borderBottom: '1px solid #e5e7eb',
                      background: `${typeInfo?.color}10`
                    }}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span style={{ color: typeInfo?.color, fontSize: '16px' }}>
                          {typeInfo?.icon}
                        </span>
                        <span style={{ color: typeInfo?.color, fontWeight: '600', fontSize: '14px' }}>
                          {typeInfo?.name}
                        </span>
                      </div>
                      
                      <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '5px', color: '#6b7280', fontSize: '12px' }}>
                          <FaUser size={10} /> {material.user}
                        </div>
                      </div>
                    </div>
                    
                    {/* Content */}
                    <div style={{ padding: '25px' }}>
                      <h4 style={{
                        fontSize: '18px',
                        fontWeight: '600',
                        color: '#1f2937',
                        marginBottom: '12px',
                        lineHeight: '1.4'
                      }}>
                        {material.title}
                      </h4>
                      <p style={{
                        color: '#6b7280',
                        fontSize: '14px',
                        lineHeight: '1.6',
                        marginBottom: '20px',
                        minHeight: '60px'
                      }}>
                        {material.description}
                      </p>
                      
                      <div style={{
                        display: 'grid',
                        gridTemplateColumns: '1fr 1fr',
                        gap: '15px',
                        marginBottom: '20px',
                        background: '#f9fafb',
                        padding: '15px',
                        borderRadius: '8px'
                      }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaClock color="#9ca3af" size={12} />
                          <span>{material.uploadDate}</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaDownload color="#9ca3af" size={12} />
                          <span>{material.downloads} downloads</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaEye color="#9ca3af" size={12} />
                          <span>{material.views} views</span>
                        </div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: '#6b7280', fontSize: '13px' }}>
                          <FaStar color="#fbbf24" size={12} />
                          <span>{material.rating}/5</span>
                        </div>
                      </div>
                      
                      <div style={{
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        paddingTop: '15px',
                        borderTop: '1px solid #e5e7eb',
                        fontSize: '13px',
                        color: '#9ca3af'
                      }}>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                          {getFileIcon(material.fileType)}
                          <span>{material.fileSize}</span>
                        </span>
                        <span style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                          📖 {material.pages} pages
                        </span>
                      </div>
                    </div>
                    
                    {/* Action Buttons */}
                    <div style={{
                      padding: '20px',
                      background: '#f9fafb',
                      borderTop: '1px solid #e5e7eb',
                      display: 'flex',
                      gap: '12px'
                    }}>
                      <button
                        style={{
                          flex: '1',
                          padding: '12px',
                          background: 'white',
                          border: '2px solid #e5e7eb',
                          borderRadius: '8px',
                          cursor: 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '8px',
                          fontWeight: '600',
                          color: '#4b5563',
                          fontSize: '14px',
                          transition: 'all 0.3s'
                        }}
                        onClick={() => handlePreview(material)}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = '#f3f4f6';
                          e.currentTarget.style.borderColor = '#d1d5db';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = 'white';
                          e.currentTarget.style.borderColor = '#e5e7eb';
                        }}
                      >
                        <FaEye size={14} /> Preview
                      </button>
                      
                      <button
                        style={{
                          flex: '2',
                          padding: '12px',
                          background: 'linear-gradient(135deg, #10b981 0%, #34d399 100%)',
                          color: 'white',
                          border: 'none',
                          borderRadius: '8px',
                          cursor: downloading[material.id] ? 'not-allowed' : 'pointer',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '8px',
                          fontWeight: '600',
                          fontSize: '14px',
                          transition: 'all 0.3s',
                          opacity: downloading[material.id] ? 0.7 : 1
                        }}
                        onClick={() => handleDownload(material)}
                        disabled={downloading[material.id]}
                        onMouseEnter={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = 'linear-gradient(135deg, #059669 0%, #10b981 100%)';
                            e.currentTarget.style.transform = 'translateY(-2px)';
                            e.currentTarget.style.boxShadow = '0 4px 12px rgba(16, 185, 129, 0.3)';
                          }
                        }}
                        onMouseLeave={(e) => {
                          if (!downloading[material.id]) {
                            e.currentTarget.style.background = 'linear-gradient(135deg, #10b981 0%, #34d399 100%)';
                            e.currentTarget.style.transform = 'none';
                            e.currentTarget.style.boxShadow = 'none';
                          }
                        }}
                      >
                        {downloading[material.id] ? (
                          <>
                            <FaSpinner style={{ animation: 'spin 1s linear infinite' }} size={14} />
                            Downloading...
                          </>
                        ) : (
                          <>
                            <FaDownload size={14} /> Download
                          </>
                        )}
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default MaterialsPage;




